    "claim": { "type": "object", "properties": {
      "policy_number": {"type":"string"}, "claimant_name": {"type":"string"}, "claimant_email": {"type":"string"},
      "incident_type": {"type":"string"}, "incident_date": {"type":"string"}, "estimated_value": {"type":"number"}, "description": {"type":"string"} } },
    "triage": { "type": "object", "properties": {
      "claim_type": {"type":"string"}, "severity": {"type":"string"}, "fraud_risk": {"type":"integer"}, "fraud_reasons": {"type":"string"},
      "vulnerable_flag": {"type":"boolean"}, "vulnerable_reason": {"type":"string"}, "routing": {"type":"string"}, "ai_summary": {"type":"string"} } }
  }
}

